const input = $input.first().json;
const compactTime = new Date().toISOString().replace(/[-:TZ.]/g, '').slice(0, 14);
return [{ json: { ...input, run_id: `mf_${compactTime}_${Math.random().toString(36).slice(2, 8)}`, submitted_at: new Date().toISOString(), source_mode: 'manual_transcript', status: 'received', prompt_version_followup: 'followup_v1.0.0', error_message: '' } }];

const item = $input.first().json;
const transcript = String(item.manual_transcript || '').trim();
const rawDemo = item.demo_data_confirmed;
const demoString = Array.isArray(rawDemo) ? rawDemo.join(' ').toLowerCase() : String(rawDemo ?? '').toLowerCase().trim();
const demo = rawDemo === true || rawDemo === 1 || ['true', 'on', 'yes', 'checked', '1', 'demo_data_confirmed'].includes(demoString) || (Array.isArray(rawDemo) && rawDemo.length > 0);
const required = {
  meeting_title: String(item.meeting_title || '').trim(),
  department: String(item.department || '').trim(),
  meeting_type: String(item.meeting_type || '').trim(),
  reviewer_name: String(item.reviewer_name || '').trim(),
};
const missingFields = Object.entries(required)
  .filter(([, value]) => !value)
  .map(([key]) => key);
const input_ok = Boolean(demo && transcript && missingFields.length === 0);
const errorBits = [];
if (!demo) errorBits.push('Demo data not confirmed.');
if (!transcript) errorBits.push('Transcript is empty.');
if (missingFields.length) errorBits.push(`Missing required fields: ${missingFields.join(', ')}.`);
return [{ json: {
  ...item,
  manual_transcript: transcript,
  meeting_title: required.meeting_title,
  department: required.department,
  meeting_type: required.meeting_type,
  reviewer_name: required.reviewer_name,
  demo_data_confirmed_raw: rawDemo,
  input_ok,
  status: input_ok ? 'received' : 'rejected_input',
  error_message: input_ok ? '' : errorBits.join(' '),
} }];

const response = $input.first().json;
const meta = $('Render Follow-up Prompt').first().json;

const raw =
  response?.choices?.[0]?.message?.content ??
  response?.body?.choices?.[0]?.message?.content ??
  response?.data?.choices?.[0]?.message?.content ??
  '';

if (!raw || typeof raw !== 'string') {
  return [{
    json: {
      ...meta,
      parse_ok: false,
      raw_model_output: raw || '',
      parse_error: 'MiniMax response missing message content'
    }
  }];
}

function stripWrappers(text) {
  return String(text || '')
    .replace(/<think>[\s\S]*?<\/think>\s*/g, '')
    .replace(/```(?:json)?/gi, '')
    .replace(/```/g, '')
    .trim();
}

function extractOuterJsonObject(text) {
  const start = text.indexOf('{');
  if (start === -1) return '';

  let inString = false;
  let escape = false;
  let depth = 0;

  for (let i = start; i < text.length; i += 1) {
    const ch = text[i];

    if (inString) {
      if (escape) {
        escape = false;
      } else if (ch === '\\') {
        escape = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    }

    if (ch === '"') {
      inString = true;
      continue;
    }

    if (ch === '{') depth += 1;
    if (ch === '}') {
      depth -= 1;
      if (depth === 0) {
        return text.slice(start, i + 1);
      }
    }
  }

  return '';
}

function sanitizeJsonLike(text) {
  return text
    .replace(/^\uFEFF/, '')
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/,\s*([}\]])/g, '$1')
    .trim();
}

function safeString(value, fallback = '') {
  if (value == null) return fallback;
  if (typeof value === 'string') return value.trim() || fallback;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return fallback;
}

function asStringArray(value) {
  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === 'string') return item.trim();
        if (item == null) return '';
        if (typeof item === 'object') {
          return safeString(
            item.text ||
            item.value ||
            item.label ||
            item.title ||
            item.name ||
            item.question ||
            item.decision ||
            item.risk ||
            item.note,
            ''
          );
        }
        return String(item).trim();
      })
      .filter(Boolean);
  }

  if (typeof value === 'string') {
    return value.trim() ? [value.trim()] : [];
  }

  if (value && typeof value === 'object') {
    const extracted = safeString(
      value.text ||
      value.value ||
      value.label ||
      value.title ||
      value.name ||
      value.question ||
      value.decision ||
      value.risk ||
      value.note,
      ''
    );
    return extracted ? [extracted] : [];
  }

  return value == null ? [] : [String(value)];
}

function normalizeFaqItems(value) {
  const items = Array.isArray(value) ? value : value && typeof value === 'object' ? [value] : [];

  return items.map((item) => {
    if (!item || typeof item !== 'object') {
      return {
        question: 'Untitled question',
        answer: ''
      };
    }

    return {
      question: safeString(item.question || item.q || item.title, 'Untitled question'),
      answer: safeString(item.answer || item.a || item.response, '')
    };
  });
}

function normalizeActionItems(value) {
  const items =
    Array.isArray(value) ? value :
    typeof value === 'string' ? [value] :
    value && typeof value === 'object' ? [value] :
    [];

  return items.map((item) => {
    if (typeof item === 'string') {
      return {
        task: item.trim() || 'not specified',
        owner: null,
        deadline: null,
        notes: ''
      };
    }

    if (!item || typeof item !== 'object') {
      return {
        task: 'not specified',
        owner: null,
        deadline: null,
        notes: ''
      };
    }

    return {
      task: safeString(
        item.task ||
        item.action ||
        item.title ||
        item.name ||
        item.label ||
        item.description ||
        item.notes,
        'not specified'
      ),
      owner: safeString(item.owner, '') || null,
      deadline: safeString(item.deadline, '') || null,
      notes: safeString(item.notes || item.note || item.details || item.context, '')
    };
  });
}

function normalizeOpportunityItems(value) {
  const items = Array.isArray(value) ? value : value && typeof value === 'object' ? [value] : [];

  return items.map((item) => {
    if (!item || typeof item !== 'object') {
      return {
        title: 'Untitled opportunity',
        impact: '',
        effort: '',
        notes: ''
      };
    }

    return {
      title: safeString(item.title || item.opportunity || item.name, 'Untitled opportunity'),
      impact: safeString(item.impact),
      effort: safeString(item.effort),
      notes: safeString(item.notes || item.note || item.rationale)
    };
  });
}

let cleaned = stripWrappers(raw);
cleaned = extractOuterJsonObject(cleaned) || cleaned;
cleaned = sanitizeJsonLike(cleaned);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  return [{
    json: {
      ...meta,
      parse_ok: false,
      raw_model_output: raw,
      cleaned_model_output: cleaned,
      parse_error: error.message
    }
  }];
}

if (!parsed || Array.isArray(parsed) || typeof parsed !== 'object') {
  return [{
    json: {
      ...meta,
      parse_ok: false,
      raw_model_output: raw,
      cleaned_model_output: cleaned,
      parse_error: 'Parsed output must be an object.'
    }
  }];
}

parsed.summary = asStringArray(parsed.summary);
parsed.key_decisions = asStringArray(parsed.key_decisions);
parsed.risks_open_questions = asStringArray(parsed.risks_open_questions);
parsed.action_items = normalizeActionItems(parsed.action_items);
parsed.employee_faq = normalizeFaqItems(parsed.employee_faq);
parsed.ai_adoption_opportunities = normalizeOpportunityItems(parsed.ai_adoption_opportunities);

if (!parsed.ai_ambassador_brief || Array.isArray(parsed.ai_ambassador_brief) || typeof parsed.ai_ambassador_brief !== 'object') {
  const brief = typeof parsed.ai_ambassador_brief === 'string' ? parsed.ai_ambassador_brief.trim() : '';
  parsed.ai_ambassador_brief = {
    headline: brief ? brief.split(/\r?\n/)[0].slice(0, 160) : 'AI follow-up brief',
    talking_points: brief ? [brief] : [],
    suggested_internal_message: brief
  };
} else {
  parsed.ai_ambassador_brief.headline = safeString(parsed.ai_ambassador_brief.headline, 'AI follow-up brief');
  parsed.ai_ambassador_brief.talking_points = asStringArray(parsed.ai_ambassador_brief.talking_points);
  parsed.ai_ambassador_brief.suggested_internal_message = safeString(parsed.ai_ambassador_brief.suggested_internal_message);
}

return [{
  json: {
    ...meta,
    parse_ok: true,
    followup: parsed,
    raw_model_output: raw,
    cleaned_model_output: cleaned,
    parse_error: ''
  }
}];

